const statusPedido = 'enviado';

switch (statusPedido) {
  case 'pendente':
    console.log('Pedido aguardando processamento.');
    break;
  case 'enviado':
    console.log('Pedido em transporte.');
    break;
  case 'entregue':
    console.log('Pedido concluído.');
    break;
  default:
    console.log('Status não reconhecido.');
}

const dia = 'sábado';

switch (dia) {
  case 'sábado':
  case 'domingo':
    console.log('Fim de semana.');
    break;
  default:
    console.log('Dia útil ou não mapeado.');
}

const nivelUsuario = 'moderador';

switch (nivelUsuario) {
  case 'administrador':
    console.log('Acesso total ao sistema.');
    break;
  case 'moderador':
    console.log('Acesso intermediário ao sistema.');
    break;
  case 'visitante':
    console.log('Acesso limitado ao sistema.');
    break;
  default:
    console.log('Nível de usuário desconhecido.');
}
